#include<bits/stdc++.h>
#define int long long
using namespace std;
const int MAXN = 1e5 + 10;
int sum[MAXN], v[MAXN], m[MAXN];
int money;
int buy;
signed main()
{
	int n, d;
	cin >> n >> d;
	for(int i = 1; i < n; i++){
		cin >> v[i];
	}
	for(int i = 1; i <= n; i++){
		cin >> m[i];
	}
	int mini = m[1], L = 0;
	for(int i = 1; i <= n; i++){
		mini = min(mini, m[i]);
		if(L > v[i])L -= v[i];
		else{

			v[i] -= L;
			buy = ceil(1.0 * v[i] / d);
			money += mini * buy;
			L = buy * d - v[i];
		}
	}
	cout << money;
}
